#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <fstream>
#include <cstdlib> // For system()
#include <cstdio>  // For remove()

// Helper function to execute the compiled program with specific input and capture its full output.
// This function assumes the student's code has been compiled into an executable named 'a.out'
// in the current directory.
std::string run_and_capture_output(const std::string& input_str) {
    std::string output_filename = "program_output.txt";
    std::string input_filename = "program_input.txt";
    std::string executable_name = "./a.out"; // Or "program.exe" on Windows

    // Write input to a temporary file
    std::ofstream input_file(input_filename);
    if (!input_file.is_open()) {
        return "Driver Error: Could not create input file.\n";
    }
    input_file << input_str << std::endl;
    input_file.close();

    // Execute the program, redirecting stdin and stdout/stderr
    // Note: This command captures both stdout and stderr to the same output file.
    std::string command = executable_name + " < " + input_filename + " > " + output_filename + " 2>&1";
    std::system(command.c_str());

    // Read the captured output
    std::ifstream output_file(output_filename);
    if (!output_file.is_open()) {
        return "Driver Error: Could not open output file.\n";
    }
    std::stringstream buffer;
    buffer << output_file.rdbuf();
    output_file.close();

    // Clean up temporary files
    std::remove(input_filename.c_str());
    std::remove(output_filename.c_str());

    return buffer.str();
}

int main() {
    std::cout << "Driver ready to execute program with test cases defined in JSON." << std::endl;
    std::cout << "Compile student's code to 'a.out' and run `run_and_capture_output` for each test case." << std::endl;
    return 0;
}
